topics.semanticHtml.sections.whenNativeI:
// Tem role, teclado e estado anunciado
// Nota: <button> ainda é preferível se o estilo permitir
<div
  role="button"
  tabIndex={0}
  aria-expanded={isOpen}
  aria-haspopup="menu"
  onClick={toggleMenu}
  onKeyDown={(e) => {
    if (e.key === 'Enter' || e.key === ' ') toggleMenu();
  }}
>
  Menu
</div>
